var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. FS001L0932-35: <color=#ffd34c>【부록-327】 관계자 증언</color>","JPN":"AEGIS 8 PBLIT SECURITY SEQUENCE：<color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR：<color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. FS001L0932-35：<color=#ffd34c>【付録-327】 関係者の証言</color>","ENG":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. FS001L0932-35: <color=#ffd34c>【Appendix-327】 Contact Testimony</color>","TWN":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. FS001L0932-35: <color=#ffd34c>【附錄-327】 相關人士證言</color>","THA":"กระบวนการตรวจสอบประวัติเพื่อความปลอดภัย AEGIS 8 PBLIT: <color=#ffd34c>เปิดทำงาน</color>     \\nADC แฟกเตอร์: <color=#ffd34c>ยืนยันในระดับอัลฟ่า</color>     \\nCCN หมายเลข FS001L0932-35: <color=#ffd34c>[เอกสารแนบท้าย-327] คำบอกเล่าจากคนรู้จัก</color>","VTN":"TRÌNH TỰ AN NINH AEGIS 8 PBLIT: <color=#ffd34c>ĐÃ KÍCH HOẠT</color>     \\nTHÔNG SỐ ADC: <color=#ffd34c>XÁC NHẬN ALPHA </color>     \\nCCN Số FS001L0932-35: <color=#ffd34c>[Phụ Lục-327] Thẩm Vấn Mối Quan Hệ</color>","SCN":"AEGIS 8 PBLIT安全序列: <color=#ffd34c>激活</color>\\nADC 因素: <color=#ffd34c>阿尔法确认</color>     \\nCCN No. FS001L0932-35: <color=#ffd34c>【附录-327】 相关人士证言</color>","DEU":"AEGIS 8 PBLIT-SICHERHEITSSEQUENZ: <color=#ffd34c>AKTIVIERT</color>     \\nADC-FAKTOR: <color=#ffd34c>ALPHA BESTÄTIGT</color>     \\nCCN-Nr. FS001L0932-35: <color=#ffd34c>【Anhang-327】 Zeugenaussage des Kontakts</color>","FRA":"AEGIS 8 PROTOCOLE DE SÉCURITÉ PBLIT\xA0: <color=#ffd34c>ACTIVÉ</color>     \\nFACTEUR CAD\xA0: <color=#ffd34c>ALPHA CONFIRMÉ</color>     \\nCCN\xA0FS001L0932-35\xA0: <color=#ffd34c>【Annexe\xA0-327】 Témoignage d'un contact</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"힐데 소대장님이요?","JPN":"ヒルデ小隊長ですか？","ENG":"Commander Hilde?","TWN":"希爾德小隊長嗎？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"음...... 처음 만났을 때가 제가 고등학교 졸업하고 처음 취업할 때였으니까.......","JPN":"えっと……初めて会ったのは高校卒業後、初めて就職した時だったから……","ENG":"Err... I met her when I got my first job after graduating high school.","TWN":"嗯……我初次見到她，是在高中畢業後第一次就業的時候……"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"......벌써 시간이 이렇게 지났네요.","JPN":"……もうそんなに経ったんですね。","ENG":"It's already been so long.","TWN":"……已經過這麼久了呢。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"참 세월 빠르다니까요?","JPN":"本当に、時が経つのは早いものです。","ENG":"Time really flies, huh?","TWN":"真是光陰似箭對吧？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"......특이한 점이요?","JPN":"……変わったところですか？","ENG":"Did I notice anything special about her?","TWN":"……她有什麼特別的地方嗎？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"글쎄요....... 요즘 세상이 워낙 살기 힘들다 보니 성격 괴팍한 거야 별로 특별할 것도 없긴 한데.......","JPN":"さあ……最近は世の中も荒れてるので、偏屈な性格は特異なこととも言えないし……","ENG":"Well... She's always cranky, but that's nothing special in this harsh world.","TWN":"這個嘛……在如今這個生活如此艱難的世界，也難怪性格會變得孤僻……"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"아, 그러고 보니 처음에 사장님이 소대장님을 스승님이라고 부르길래 깜짝 놀랐다니까요?","JPN":"あ、そういえば社長が小隊長を師匠と呼ぶのには、本当に驚きましたね。","ENG":"Oh, I was really surprised at first when our CEO called her Master.","TWN":"啊，對了，剛開始聽到老闆叫小隊長「師父」時，嚇了我一跳。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"그때는 무슨 벌칙 게임 같은 건가 했는데.......","JPN":"初めて見た時は、罰ゲームだと思ったけど……","ENG":"I thought it was some sort of punishment.","TWN":"我還以為是什麼懲罰遊戲呢……"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"그 꼬맹이....... 아니, 소대장님이 그렇게 나이가 많을 줄 누가 알았겠어요?","JPN":"あのチビ……いや、小隊長があんなに年を取ってるとは思いませんでした。","ENG":"Who would have guessed that brat—I mean, commander—was so old?","TWN":"那個矮子……不是，誰能想到小隊長的年紀竟然這麼大呢？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"한동안 쉬시다가 며칠 전에 복귀하신 것 같은데.......","JPN":"しばらく休んで、数日前に復帰したみたいですけど……","ENG":"She returned a few days ago after taking a long break.","TWN":"好像是休息了一段時間，幾天前才回來……"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"역시나 그 어린 모습은 전혀 변함이 없더라고요.","JPN":"やっぱり、あの子供みたいな外見は変わってませんでした。","ENG":"And her appearance hasn't changed at all.","TWN":"果然那個年輕的樣貌完全沒有變化。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"부러워라.......","JPN":"羨ましいな……","ENG":"I'm so jealous of her.","TWN":"好羡慕喔……"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"비결이요? 글쎄요....... 역시 화장품 아닐까요?","JPN":"秘訣ですか？　さあ……やっぱり化粧品じゃないですか？","ENG":"Her secret? Well... her cosmetics, I guess?","TWN":"秘訣嗎？嗯……果然是化妝品吧？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"시윤 군에게 슬쩍 물어 봤는데 이터니움으로 만든 초고가의 특수 안티에이징 크림을 쓴다는 이야기도 있고.......","JPN":"アキヤマ君にこっそり聞いてみたんですが、エタニウム製の超高価な特殊アンチエイジング・クリームを使っているという噂も……","ENG":"I asked Shiyoon once, and he told me that she uses an expensive anti-aging cream made with Eternium.","TWN":"我偷偷問了一下時雲君，好像說是用一種永恆之金製作的超貴特殊抗衰老面霜。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"하지만 그 ","JPN":"しかし、あの ","ENG":"But it's ","TWN":"但那是……"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":"주. 시. 윤.","JPN":"アキヤマ・シリュウ君","ENG":"Joo. Shi. Yoon.","TWN":"周．時．雲．"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RECORD_VOICE_NULL_NULL","text":{"KOREA":" 군 말이니까요.","JPN":"の話ですから。","ENG":" we're talking about.","TWN":"君說的話。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};